import{_ as l,o as t,c as r,ag as i}from"./chunks/framework.ePeAWSvT.js";const g=JSON.parse('{"title":"Screen Policy: 마이페이지 > 포인트 내역","description":"","frontmatter":{},"headers":[],"relativePath":"마이페이지_포인트내역_Screen_Policy_Final.md","filePath":"마이페이지_포인트내역_Screen_Policy_Final.md"}'),e={name:"마이페이지_포인트내역_Screen_Policy_Final.md"};function n(o,a,s,h,d,u){return t(),r("div",null,[...a[0]||(a[0]=[i(`<h1 id="screen-policy-마이페이지-포인트-내역" tabindex="-1">Screen Policy: 마이페이지 &gt; 포인트 내역 <a class="header-anchor" href="#screen-policy-마이페이지-포인트-내역" aria-label="Permalink to &quot;Screen Policy: 마이페이지 &gt; 포인트 내역&quot;">​</a></h1><h2 id="■-screen-meta" tabindex="-1">■ Screen Meta <a class="header-anchor" href="#■-screen-meta" aria-label="Permalink to &quot;■ Screen Meta&quot;">​</a></h2><ul><li><strong>SCREEN_NAME</strong>: 마이페이지 &gt; 포인트 내역</li><li><strong>화면 목적</strong>: 회원의 포인트 적립/사용/소멸 이력 조회</li><li><strong>화면 형태</strong>: 단일 페이지 (필터 + 목록)</li><li><strong>접근 대상</strong>: 로그인 회원 전용</li><li><strong>기능 범위</strong>: 조회 전용 (포인트 사용 기능 없음)</li></ul><hr><h2 id="■-화면-구조" tabindex="-1">■ 화면 구조 <a class="header-anchor" href="#■-화면-구조" aria-label="Permalink to &quot;■ 화면 구조&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[마이페이지 &gt; 포인트 내역]</span></span>
<span class="line"><span>  ├─ [상단] 보유 포인트 요약</span></span>
<span class="line"><span>  ├─ [필터] 기간 검색 (Date Picker)</span></span>
<span class="line"><span>  ├─ [목록] 포인트 내역 리스트</span></span>
<span class="line"><span>  │     ├─ 날짜</span></span>
<span class="line"><span>  │     ├─ 구분 (적립 / 사용 / 소멸)</span></span>
<span class="line"><span>  │     ├─ 내용 (접수번호 포함)</span></span>
<span class="line"><span>  │     └─ 포인트 (+ / -)</span></span>
<span class="line"><span>  └─ [페이지네이션]</span></span></code></pre></div><hr><h2 id="■-field-rule" tabindex="-1">■ Field Rule <a class="header-anchor" href="#■-field-rule" aria-label="Permalink to &quot;■ Field Rule&quot;">​</a></h2><hr><h3 id="기간-필터" tabindex="-1">[기간 필터] <a class="header-anchor" href="#기간-필터" aria-label="Permalink to &quot;[기간 필터]&quot;">​</a></h3><h4 id="기간-입력-방식" tabindex="-1">[기간 입력 방식] <a class="header-anchor" href="#기간-입력-방식" aria-label="Permalink to &quot;[기간 입력 방식]&quot;">​</a></h4><ul><li><strong>UI 유형</strong>: Range Date Picker (시작일 ~ 종료일)</li><li><strong>기본값</strong>: 최근 1개월 (오늘 기준 1개월 전 ~ 오늘)</li><li><strong>선택 방식</strong>: 달력 UI에서 시작일과 종료일 범위 선택</li><li><strong>UI 정책</strong>: <ul><li>시작일 선택 후 종료일 선택하는 순서로 진행</li><li>시작일 &gt; 종료일 설정 불가 (역방향 선택 방지)</li><li>선택된 기간 범위는 달력 내 하이라이트 표시</li><li>기간 초기화 버튼 제공 (초기화 시 기본값 최근 1개월로 복귀)</li></ul></li></ul><h4 id="빠른-기간-선택-버튼" tabindex="-1">[빠른 기간 선택 버튼] <a class="header-anchor" href="#빠른-기간-선택-버튼" aria-label="Permalink to &quot;[빠른 기간 선택 버튼]&quot;">​</a></h4><ul><li><strong>제공 여부</strong>: 제공</li><li><strong>선택 항목</strong>: 최근 1개월 / 최근 6개월 / 최근 1년</li><li><strong>UI 정책</strong>: <ul><li>버튼 클릭 시 해당 기간으로 Date Picker 자동 설정</li><li>기본 선택 상태: 최근 1개월</li></ul></li></ul><hr><h3 id="포인트-구분-필터" tabindex="-1">[포인트 구분 필터] <a class="header-anchor" href="#포인트-구분-필터" aria-label="Permalink to &quot;[포인트 구분 필터]&quot;">​</a></h3><ul><li><strong>필수 여부</strong>: 선택 (기본값: 전체)</li><li><strong>선택 항목</strong>: 전체 / 적립 / 사용 / 소멸</li><li><strong>UI 정책</strong>: <ul><li>탭 또는 버튼형 단일 선택</li><li>선택 시 해당 구분의 내역만 목록에 표시</li><li>기간 필터와 구분 필터 동시 적용</li></ul></li></ul><hr><h3 id="포인트-내역-목록" tabindex="-1">[포인트 내역 목록] <a class="header-anchor" href="#포인트-내역-목록" aria-label="Permalink to &quot;[포인트 내역 목록]&quot;">​</a></h3><h4 id="목록-표시-항목" tabindex="-1">[목록 표시 항목] <a class="header-anchor" href="#목록-표시-항목" aria-label="Permalink to &quot;[목록 표시 항목]&quot;">​</a></h4><ul><li><strong>날짜</strong>: 포인트 적립/사용/소멸 발생일 (YYYY-MM-DD 형식)</li><li><strong>구분</strong>: 적립 / 사용 / 소멸</li><li><strong>내용</strong>: 포인트 발생 사유 (접수번호 포함 시 링크/버튼 형태로 표시)</li><li><strong>포인트</strong>: <ul><li>적립: 양수 표시 (예: +1,000P)</li><li>사용/소멸: 음수 표시 (예: -500P)</li></ul></li></ul><h4 id="접수번호-클릭-동작" tabindex="-1">[접수번호 클릭 동작] <a class="header-anchor" href="#접수번호-클릭-동작" aria-label="Permalink to &quot;[접수번호 클릭 동작]&quot;">​</a></h4><ul><li><strong>UI 형태</strong>: 링크 또는 버튼 형태로 표시</li><li><strong>클릭 동작</strong>: 접수번호 상세 다이얼로그 노출</li><li><strong>다이얼로그 내용</strong>: 해당 접수 건 상세 정보 표시</li><li><strong>다이얼로그 닫기</strong>: [닫기] 버튼 또는 외부 영역 클릭 시 닫힘</li></ul><hr><h3 id="페이지네이션" tabindex="-1">[페이지네이션] <a class="header-anchor" href="#페이지네이션" aria-label="Permalink to &quot;[페이지네이션]&quot;">​</a></h3><h4 id="페이지당-표시-건수" tabindex="-1">[페이지당 표시 건수] <a class="header-anchor" href="#페이지당-표시-건수" aria-label="Permalink to &quot;[페이지당 표시 건수]&quot;">​</a></h4><ul><li><strong>선택 옵션</strong>: 10건 / 20건 / 50건 / 100건</li><li><strong>기본값</strong>: 20건</li><li><strong>UI 정책</strong>: Dropdown 방식으로 건수 선택</li></ul><h4 id="페이지-이동" tabindex="-1">[페이지 이동] <a class="header-anchor" href="#페이지-이동" aria-label="Permalink to &quot;[페이지 이동]&quot;">​</a></h4><ul><li><strong>UI 유형</strong>: 번호형 페이지네이션</li><li><strong>이동 방식</strong>: 이전 / 다음 / 페이지 번호 직접 클릭</li></ul><hr><h2 id="■-보유-포인트-요약-영역" tabindex="-1">■ 보유 포인트 요약 영역 <a class="header-anchor" href="#■-보유-포인트-요약-영역" aria-label="Permalink to &quot;■ 보유 포인트 요약 영역&quot;">​</a></h2><h3 id="표시-항목" tabindex="-1">[표시 항목] <a class="header-anchor" href="#표시-항목" aria-label="Permalink to &quot;[표시 항목]&quot;">​</a></h3><ul><li><strong>보유 포인트</strong>: 현재 사용 가능한 잔여 포인트 (단위: P)</li><li><strong>소멸 예정 포인트</strong>: 30일 이내 소멸 예정 포인트 및 소멸 예정일 표시 <ul><li>표시 조건: 30일 이내 소멸 예정 포인트가 존재하는 경우에만 노출</li><li>표시 예시: &quot;30일 이내 소멸 예정 포인트: 500P (2025-11-30)&quot;</li></ul></li></ul><hr><h2 id="■-기능-범위" tabindex="-1">■ 기능 범위 <a class="header-anchor" href="#■-기능-범위" aria-label="Permalink to &quot;■ 기능 범위&quot;">​</a></h2><h3 id="포인트-사용" tabindex="-1">[포인트 사용] <a class="header-anchor" href="#포인트-사용" aria-label="Permalink to &quot;[포인트 사용]&quot;">​</a></h3><ul><li><strong>제공 여부</strong>: 이 화면에서 포인트 사용 기능 없음</li><li><strong>이유</strong>: 조회 전용 화면</li><li><strong>포인트 사용 경로</strong>: 결제 화면에서 별도 제공</li></ul><hr><h2 id="■-세금계산서-발급-정책" tabindex="-1">■ 세금계산서 발급 정책 <a class="header-anchor" href="#■-세금계산서-발급-정책" aria-label="Permalink to &quot;■ 세금계산서 발급 정책&quot;">​</a></h2><h3 id="발급-기준" tabindex="-1">[발급 기준] <a class="header-anchor" href="#발급-기준" aria-label="Permalink to &quot;[발급 기준]&quot;">​</a></h3><ul><li><strong>발급 대상 금액</strong>: 포인트 사용 후 실제 결제 금액에 한하여 발급 가능</li><li><strong>발급 불가 금액</strong>: 포인트로 차감된 금액은 세금계산서 발급 대상에서 제외</li><li><strong>예시</strong>: <ul><li>주문 금액 100,000원 / 포인트 사용 10,000원 / 실 결제금액 90,000원</li><li>→ 세금계산서 발급 가능 금액: 90,000원</li></ul></li></ul><hr><h2 id="■-포인트-사용-정책" tabindex="-1">■ 포인트 사용 정책 <a class="header-anchor" href="#■-포인트-사용-정책" aria-label="Permalink to &quot;■ 포인트 사용 정책&quot;">​</a></h2><h3 id="최소-사용-금액" tabindex="-1">[최소 사용 금액] <a class="header-anchor" href="#최소-사용-금액" aria-label="Permalink to &quot;[최소 사용 금액]&quot;">​</a></h3><ul><li><strong>최소 사용 포인트</strong>: 10,000P (임시 확정, 오픈 전 최종 확정 필요)</li><li><strong>적용 기준</strong>: 1회 결제 시 사용 가능한 최소 포인트 단위</li></ul><hr><h2 id="■-화면-결과" tabindex="-1">■ 화면 결과 <a class="header-anchor" href="#■-화면-결과" aria-label="Permalink to &quot;■ 화면 결과&quot;">​</a></h2><h3 id="조회-성공-시" tabindex="-1">[조회 성공 시] <a class="header-anchor" href="#조회-성공-시" aria-label="Permalink to &quot;[조회 성공 시]&quot;">​</a></h3><ul><li>설정된 기간에 해당하는 포인트 내역 목록 표시</li><li>결과 없을 경우: &quot;해당 기간에 포인트 내역이 없어요&quot; 안내 문구 표시</li></ul><h3 id="접수번호-클릭-시" tabindex="-1">[접수번호 클릭 시] <a class="header-anchor" href="#접수번호-클릭-시" aria-label="Permalink to &quot;[접수번호 클릭 시]&quot;">​</a></h3><ul><li>해당 접수번호 상세 다이얼로그 노출</li></ul><hr><h2 id="■-예외-상황" tabindex="-1">■ 예외 상황 <a class="header-anchor" href="#■-예외-상황" aria-label="Permalink to &quot;■ 예외 상황&quot;">​</a></h2><h3 id="네트워크-오류-시" tabindex="-1">[네트워크 오류 시] <a class="header-anchor" href="#네트워크-오류-시" aria-label="Permalink to &quot;[네트워크 오류 시]&quot;">​</a></h3><ul><li><strong>처리</strong>: 에러 메시지 표시</li><li><strong>메시지</strong>: &quot;일시적인 오류가 발생했습니다. 다시 시도해주세요&quot;</li><li><strong>재시도</strong>: 사용자가 재조회 가능</li></ul><h3 id="서버-오류-시" tabindex="-1">[서버 오류 시] <a class="header-anchor" href="#서버-오류-시" aria-label="Permalink to &quot;[서버 오류 시]&quot;">​</a></h3><ul><li><strong>처리</strong>: 에러 메시지 표시</li><li><strong>메시지</strong>: &quot;일시적인 오류가 발생했습니다. 잠시 후 다시 시도해주세요&quot;</li></ul><h3 id="조회-결과-없음-시" tabindex="-1">[조회 결과 없음 시] <a class="header-anchor" href="#조회-결과-없음-시" aria-label="Permalink to &quot;[조회 결과 없음 시]&quot;">​</a></h3><ul><li><strong>처리</strong>: 빈 목록 상태로 표시</li><li><strong>안내 문구</strong>: &quot;해당 기간에 포인트 내역이 없어요&quot;</li></ul><hr><h2 id="■-현업-확인-필요사항" tabindex="-1">■ 현업 확인 필요사항 <a class="header-anchor" href="#■-현업-확인-필요사항" aria-label="Permalink to &quot;■ 현업 확인 필요사항&quot;">​</a></h2><h3 id="⚠️-오픈-전-확정-필요" tabindex="-1">⚠️ 오픈 전 확정 필요 <a class="header-anchor" href="#⚠️-오픈-전-확정-필요" aria-label="Permalink to &quot;⚠️ 오픈 전 확정 필요&quot;">​</a></h3><ul><li><strong>포인트 최소 사용 금액</strong>: 현재 10,000P로 임시 확정된 상태이며, 서비스 오픈 전 최종 확정 필요</li></ul><hr><h2 id="■-필요-화면-목록" tabindex="-1">■ 필요 화면 목록 <a class="header-anchor" href="#■-필요-화면-목록" aria-label="Permalink to &quot;■ 필요 화면 목록&quot;">​</a></h2><p>현재 화면 플로우에서 필요하지만 제공되지 않은 화면:</p><ol><li><strong>접수번호 상세 다이얼로그</strong><ul><li>필요 사유: 포인트 내역 목록에서 접수번호 클릭 시 노출</li><li>기능: 해당 접수 건의 상세 정보 조회</li></ul></li></ol><hr><h2 id="■-확정된-정책-요약" tabindex="-1">■ 확정된 정책 요약 <a class="header-anchor" href="#■-확정된-정책-요약" aria-label="Permalink to &quot;■ 확정된 정책 요약&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>확정 내용</th></tr></thead><tbody><tr><td>기간 필터 UI</td><td>Range Date Picker (시작일 ~ 종료일)</td></tr><tr><td>기간 기본값</td><td>최근 1개월</td></tr><tr><td>빠른 기간 선택</td><td>최근 1개월 / 최근 6개월 / 최근 1년</td></tr><tr><td>포인트 구분 필터</td><td>전체 / 적립 / 사용 / 소멸</td></tr><tr><td>페이지당 건수 옵션</td><td>10건 / 20건 / 50건 / 100건</td></tr><tr><td>페이지당 기본 건수</td><td>20건</td></tr><tr><td>접수번호 클릭</td><td>상세 다이얼로그 표시</td></tr><tr><td>소멸 예정 포인트</td><td>30일 이내 소멸 예정 포인트 및 소멸 예정일 표시</td></tr><tr><td>포인트 사용 기능</td><td>없음 (조회 전용)</td></tr><tr><td>포인트 최소 사용 금액</td><td>10,000P (임시 확정 / 오픈 전 최종 확정 필요)</td></tr><tr><td>세금계산서 발급</td><td>포인트 사용 후 실 결제금액에 한하여 발급 가능 (포인트 차감분 제외)</td></tr></tbody></table>`,70)])])}const b=l(e,[["render",n]]);export{g as __pageData,b as default};
